repos = ["cocodrilo-fitness", "luis-de-leon-concept", "bichos-gym", "mantra-spa", "magnolia-peluqueria"]

# 3. Create content directory with a basic site config
content_json = '''{
  "site": {
    "theme": {
      "primary": "#0d2137",
      "secondary": "#2ecc71",
      "background": "#f8f9fa"
    },
    "fonts": {
      "heading": "Playfair Display",
      "body": "Montserrat"
    },
    "seo": {
      "ogImage": "/images/og-default.jpg",
      "twitterHandle": ""
    }
  }
}
'''

# Create the content directory and write config for each
for r in repos:
    terminal(f"mkdir -p /root/{r}/content /root/{r}/public/images /root/{r}/app/api/subscribe 2>&1", workdir="/root")
    write_file(f"/root/{r}/content/site.json", content_json)

    # Also create robots.ts
    robots = '''import type { MetadataRoute } from "next"
export default function robots(): MetadataRoute.Robots {
  return {
    rules: { userAgent: "*", allow: "/" },
    sitemap: "https://''' + r + '''.paragu-ai.com/sitemap.xml",
  }
}
'''
    write_file(f"/root/{r}/app/robots.ts", robots)

    # Create sitemap.ts
    sitemap = '''import type { MetadataRoute } from "next"
export default function sitemap(): MetadataRoute.Sitemap {
  const domain = "https://''' + r + '''.paragu-ai.com"
  const pages = ["/", "/servicios", "/contacto", "/nosotros", "/faq", "/privacidad", "/terminos"]
  return pages.map(page => ({
    url: `${domain}${page}`,
    lastModified: new Date(),
    changeFrequency: page === "/" ? "weekly" : "monthly",
    priority: page === "/" ? 1.0 : 0.6,
  }))
}
'''
    write_file(f"/root/{r}/app/sitemap.ts", sitemap)

    print(f"Added content/, robots, sitemap for {r}")
"}

